INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078002, 0.0, 10078, 1, 53, 2, -416.5, 3.099, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078003, 0.0, 10078, 1, 54, 3, -416.5, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078004, 0.0, 10078, 2, 54, 4, -416.5, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 2, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078005, 0.0, 10078, 1, 57, 5, -416.5, 0.0, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 1, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078006, 0.0, 10078, 1, 55, 1, -363.0, 5.506, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 2, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078007, 0.0, 10078, 2, 55, 2, -363.0, 1.216, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 1, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078008, 0.0, 10078, 2, 56, 3, -363.0, 1.539, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 1, "カリン", 190801, "2021/10/31 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2021/11/18 14:59:59", 10078009, 0.0, 10078, 2, 56, 4, -363.0, 1.875, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 1, "カリン", 190801, "2021/10/31 12:00:00");
