INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2022/02/24 14:59:59", 10085003, 0.0, 10085, 1, 54, 3, -416.5, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, "カリン", 190801, "2022/02/07 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2022/02/24 14:59:59", 10085004, 0.0, 10085, 2, 54, 4, -416.5, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 2, "カリン", 190801, "2022/02/07 12:00:00");
