INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2022/02/24 14:59:59", 10085006, 0.0, 10085, 1, 55, 1, -363.0, 5.506, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 2, "カリン", 190801, "2022/02/07 12:00:00");
