INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2022/02/24 14:59:59", 10085008, 0.0, 10085, 2, 56, 3, -363.0, 1.539, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 1, "カリン", 190801, "2022/02/07 12:00:00");
INSERT INTO `v1_43911e1d836ad9a55922875977bc5f71934942e1a8807c3ab585e304401e84c0` VALUES ("2022/02/24 14:59:59", 10085009, 0.0, 10085, 2, 56, 4, -363.0, 1.875, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 1, "カリン", 190801, "2022/02/07 12:00:00");
